mapper.select:
SELECT m.id, m.team_id AS teamId, m.user_id AS userId, m.role, m.status, m.join_time AS joinTime, t.name AS teamName, u.nick_name AS userName FROM member m LEFT JOIN team t ON m.team_id = t.id LEFT JOIN sys_user u ON m.user_id = u.user_id WHERE m.status = 1
AND m.team_id = #{teamId}
AND m.user_id = #{userId}
AND u.nick_name LIKE CONCAT('%', #{userName}, '%')
ORDER BY m.join_time DESC
